/// The resonance between two holonomic orbs.
///
/// Constructive interference: two waves of matching frequency
/// combine, amplitudes add. The signal RISES from the noise.
///
/// Destructive interference: mismatched frequencies cancel.
/// The signal dissolves. The data remains holonomically present
/// but luminally invisible.
#[derive(Debug, Clone)]
pub struct Resonance {
    /// The interference strength — how well the two orbs resonate.
    /// High = constructive interference. Zero = no resonance.
    /// Negative would be destructive, but we measure magnitude (L1).
    pub strength: Q,
    /// The combined amplitude — sum of resonating amplitudes.
    /// Only meaningful when strength > 0.
    pub combined_amplitude: Q,
    /// The manifested frequency — the frequency that RISES
    /// from the constructive interference.
    pub manifested_frequency: Q,
    /// Phase alignment quality — how close the phases are.
    /// 0 = perfect alignment. Higher = more misaligned.
    pub phase_alignment: Q,
}

/// Compute the resonance between two holonomic orbs.
///
/// This is the non-local retrieval mechanism. The query orb
/// (the request) interferes with the stored orb (the data).
/// If they resonate, the data manifests. If not, silence.
pub fn interfere(query: &HolonomicOrb, stored: &HolonomicOrb) -> Resonance {
    // Phase alignment: |phase_query - phase_stored|
    let phase_alignment = (&query.phase - &stored.phase).abs();

    // Frequency match: how close are the torsion orders?
    // Resonance occurs when torsion orders share a common period.
    let freq_diff = (&query.torsion_order - &stored.torsion_order).abs();

    // Resonance strength: 1 / (1 + freq_diff + phase_alignment)
    // Perfect match (freq_diff=0, phase_alignment=0) → strength=1
    // Total mismatch → strength→0
    let one = Q::one();
    let strength = &one / (&one + &freq_diff + &phase_alignment);

    // Combined amplitude: constructive interference
    // amplitude = query.amplitude * stored.amplitude * strength
    let combined_amplitude = &query.luminal.amplitude
        * &stored.luminal.amplitude
        * &strength;

    // Manifested frequency: weighted average of the two frequencies,
    // weighted by their amplitudes. The stronger signal dominates.
    let total_amp = &query.luminal.amplitude + &stored.luminal.amplitude;
    let manifested_frequency = if total_amp.is_zero() {
        Q::zero()
    } else {
        (&query.luminal.frequency_thz * &query.luminal.amplitude
            + &stored.luminal.frequency_thz * &stored.luminal.amplitude)
            / &total_amp
    };

    Resonance {
        strength,
        combined_amplitude,
        manifested_frequency,
        phase_alignment,
    }
}

