#[derive(Debug, Clone)]
pub struct PhaseLock {
    /// The two orbs that are phase-locked.
    pub orb_a_index: usize,
    pub orb_b_index: usize,
    /// The phase gap at lock — should be zero or near-zero.
    pub phase_gap: Q,
    /// The shared H^1 class — what remains when the illusion dissolves.
    /// coboundary_reduce(h1_a + h1_b). The common curvature.
    pub shared_class: Delta,
    /// The unified amplitude — constructive interference at its maximum.
    /// Both luminal orbs vibrating at the same frequency.
    pub unified_amplitude: Q,
}

/// Attempt phase-lock between two holonomic orbs.
///
/// Phase-lock occurs when the phase gap between two orbs dissolves.
/// This is not forced — it is measured. The algebra discovers
/// whether the orbs are the same pattern at different angles.
///
/// Returns PhaseLock with the measured gap. The caller interprets
/// the gap magnitude — no boolean gate (Law I). A gap of zero
/// is perfect love. A small gap is approaching love. A large gap
/// is separation.
pub fn attempt_phase_lock(
    orb_a: &HolonomicOrb,
    orb_b: &HolonomicOrb,
    orb_a_index: usize,
    orb_b_index: usize,
) -> PhaseLock {
    // The phase gap between the two observation angles
    let phase_gap = (&orb_a.phase - &orb_b.phase).abs();

    // The shared H^1 class: sum of the two interference patterns,
    // coboundary_reduced. What is COMMON to both, with distortion removed.
    let shared_class = {
        let dim = orb_a.h1_class.dim;
        let m = orb_a.h1_class.m;

        if dim == orb_b.h1_class.dim && m == orb_b.h1_class.m {
            let mut combined = Delta::zero(dim, m);
            for i in 0..dim {
                for j in 0..dim {
                    for l in 0..m {
                        combined.entries[i][j][l] =
                            &orb_a.h1_class.entries[i][j][l]
                            + &orb_b.h1_class.entries[i][j][l];
                    }
                }
            }
            coboundary_reduce(&mut combined);
            combined
        } else {
            Delta::zero(1, 1)
        }
    };

    // Unified amplitude: when phase-locked, amplitudes add (constructive)
    // Scaled by proximity to lock: amplitude * (1 / (1 + phase_gap))
    let one = Q::one();
    let lock_factor = &one / (&one + &phase_gap);
    let unified_amplitude = (&orb_a.luminal.amplitude + &orb_b.luminal.amplitude)
        * &lock_factor;

    PhaseLock {
        orb_a_index,
        orb_b_index,
        phase_gap,
        shared_class,
        unified_amplitude,
    }
}

/// Is this phase-lock love? Returns the gap — the caller measures.
