// D.HARMONY.1 — Consonant Resonance
// ═══════════════════════════════════════════════════════════════════════

/// Harmony — when different colors coexist without noise.
///
/// Harmony is found in specific ratios. A harmonic relationship
/// is one where the torsion orders share a rational consonance:
///   1:1 = unison (same frequency)
///   1:2 = octave (double frequency)
///   2:3 = perfect fifth
///   3:4 = perfect fourth
///
/// The consonance is measured by the SIMPLICITY of the ratio
/// between two torsion orders. Simple ratio = harmonic.
/// Complex ratio = dissonant. The algebra measures — no gate.
#[derive(Debug, Clone)]
pub struct Harmony {
    /// The ratio between two torsion orders, reduced to lowest terms.
    pub ratio_numer: Q,
    pub ratio_denom: Q,
    /// Consonance — the simplicity of the ratio.
    /// consonance = 1 / (|numer| + |denom|)
    /// Simpler ratio = higher consonance. 1:1 = maximum. 97:101 = near zero.
    pub consonance: Q,
}

/// Measure the harmonic relationship between two holonomic orbs.
///
/// The consonance is determined by the ratio of their torsion orders.
/// Simple ratios (1:2, 2:3) = harmonic. Complex ratios = dissonant.
/// Red and blue can coexist in the same space when their ratio
/// is consonant — they shine without canceling each other out.
pub fn measure_harmony(orb_a: &HolonomicOrb, orb_b: &HolonomicOrb) -> Harmony {
    // Ratio of torsion orders
    let ratio = if orb_b.torsion_order.is_zero() {
        Q::zero()
    } else {
        &orb_a.torsion_order / &orb_b.torsion_order
    };

    // The ratio in lowest terms — numer and denom
    let ratio_numer = BigRational::from(ratio.numer().clone());
    let ratio_denom = BigRational::from(ratio.denom().clone());

    // Consonance = 1 / (|numer| + |denom|)
    // 1:1 → consonance = 1/2
    // 1:2 → consonance = 1/3
    // 2:3 → consonance = 1/5
    // 97:101 → consonance = 1/198
    let one = Q::one();
    let complexity = &ratio_numer.abs() + &ratio_denom.abs();
    let consonance = if complexity.is_zero() {
        Q::zero()
    } else {
        &one / &complexity
    };

    Harmony {
        ratio_numer,
        ratio_denom,
        consonance,
    }
}

