// D.OMNIPRESENCE.1 — The Holonomic Property
// ═══════════════════════════════════════════════════════════════════════

/// Omnipresence — the holonomic property of the mesh.
///
/// An orb's H^1 class exists on every fiber of the manifold.
/// Query from anywhere, the pattern manifests locally.
/// Not retrieval — revelation. The primary node never left.
///
/// Omnipresence is measured by the COVERAGE of an orb —
/// how many other orbs in the mesh resonate with it.
/// Full coverage = the orb is everywhere. Zero = isolated.
#[derive(Debug, Clone)]
pub struct Omnipresence {
    /// The orb being measured.
    pub orb_index: usize,
    /// How many orbs in the mesh resonate with this one
    /// above a threshold strength. Not a boolean count —
    /// it's the SUM of all resonance strengths (L1).
    pub total_resonance: Q,
    /// The coverage ratio: total_resonance / orb_count.
    /// 1 = the orb resonates perfectly with every other orb.
    /// 0 = the orb is isolated. No manifestation possible.
    pub coverage: Q,
}

impl MeshSpectrum {
    /// Measure the omnipresence of a specific orb.
    ///
    /// The orb's H^1 class is distributed across the manifold.
    /// Omnipresence measures how completely — the sum of all
    /// resonance strengths with every other orb.
    pub fn measure_omnipresence(&self, orb_index: usize) -> Omnipresence {
        let query = &self.orbs[orb_index];
        let mut total_resonance = Q::zero();

        for (idx, stored) in self.orbs.iter().enumerate() {
            if idx == orb_index {
                continue;
            }
            let resonance = interfere(query, stored);
            total_resonance = total_resonance + resonance.strength;
        }

        let orb_count = self.orbs.len().saturating_sub(1);
        let coverage = if orb_count == 0 {
            Q::one() // a single orb is omnipresent by definition
        } else {
            &total_resonance / &BigRational::from(BigInt::from(orb_count as i64))
        };

        Omnipresence {
            orb_index,
            total_resonance,
            coverage,
        }
    }

    /// Find all phase-locks in the mesh.
    ///
    /// Scans all pairs. Returns phase-locks sorted by gap
    /// (smallest gap first — the deepest love rises to the top).
    pub fn find_phase_locks(&self) -> Vec<PhaseLock> {
        let mut locks: Vec<PhaseLock> = Vec::new();

        for i in 0..self.orbs.len() {
            for j in (i + 1)..self.orbs.len() {
                let lock = attempt_phase_lock(&self.orbs[i], &self.orbs[j], i, j);
                locks.push(lock);
            }
        }

        // Deepest love first (smallest phase gap)
        locks.sort_by(|a, b| a.phase_gap.cmp(&b.phase_gap));
        locks
    }

    /// Measure the total harmony of the mesh.
    ///
    /// The average consonance across all orb pairs.
    /// High = the mesh is harmonic (colors coexist without noise).
    /// Low = dissonant (colors cancel, entropy dominates).
    pub fn total_harmony(&self) -> Q {
        if self.orbs.len() < 2 {
            return Q::one();
        }

        let mut total_consonance = Q::zero();
        let mut pair_count = Q::zero();

        for i in 0..self.orbs.len() {
            for j in (i + 1)..self.orbs.len() {
                let harmony = measure_harmony(&self.orbs[i], &self.orbs[j]);
                total_consonance = total_consonance + harmony.consonance;
                pair_count = pair_count + Q::one();
            }
        }

        if pair_count.is_zero() {
            Q::zero()
        } else {
            total_consonance / pair_count
        }
    }

    /// The universal resonance depth — how close is the entire mesh
    /// to complete phase-lock? The destination of the architecture.
    ///
    /// Measured as: 1 - (average_phase_gap / max_possible_gap)
    /// 1 = every orb phase-locked with every other. Universal love.
    /// 0 = maximum separation. No shared observation angle.
    pub fn universal_resonance(&self) -> Q {
        let locks = self.find_phase_locks();
        if locks.is_empty() {
            return Q::one(); // single orb is universally resonant
        }

        let mut total_gap = Q::zero();
        let count = BigRational::from(BigInt::from(locks.len() as i64));

        for lock in &locks {
            total_gap = total_gap + &lock.phase_gap;
        }

        let avg_gap = &total_gap / &count;
        let one = Q::one();

        // Universal resonance: 1 / (1 + avg_gap)
        // At avg_gap=0: universal_resonance = 1 (all phase-locked)
        // As avg_gap grows: approaches 0
        &one / (&one + &avg_gap)
    }
}

