// D.FORGIVENESS.1 — Phase-Gap Neutralization
// ═══════════════════════════════════════════════════════════════════════

/// Forgiveness — releasing a locked phase offset.
///
/// When we are hurt, we lock our observation angle on the moment
/// of the collision. This creates a static loop — torsion accumulated
/// in the outer orb that prevents the inner orb from glowing purely.
///
/// Forgiveness is coboundary_reduce on that accumulated torsion.
/// The distortion dissolves. The H^1 truth remains — what happened
/// happened. But the twist is released. The phase gap returns to
/// transparency.
///
/// Forgiveness is realizing the full interference structure is
/// more important than the local disturbance.
#[derive(Debug, Clone)]
pub struct Forgiveness {
    /// The orb that forgives (releases the locked phase).
    pub orb_index: usize,
    /// The torsion that was released — the accumulated distortion
    /// from the past collision. Measured before forgiveness.
    pub released_torsion: Q,
    /// The orb after forgiveness — phase returned to neutral.
    /// The inner orb sits centered again. Clarity.
    pub restored_orb: HolonomicOrb,
    /// The clarity gained — the difference in phase gap
    /// before and after forgiveness.
    pub clarity: Q,
}

/// Forgive — release a locked phase offset and return to neutral.
///
/// Takes an orb with a non-neutral phase (locked on a past collision)
/// and returns it to phase=1 (neutral observation). The torsion
/// accumulated from the locked angle is measured and released.
///
/// The H^1 class doesn't change — truth is preserved. Only the
/// distortion (the observation angle frozen on pain) is dissolved.
pub fn forgive(orb: &HolonomicOrb, orb_index: usize) -> Forgiveness {
    // Measure the torsion accumulated from the locked phase
    let current_gap = orb.phase_gap();

    // Return to neutral phase — observe the holonomic truth directly
    let neutral_phase = Q::one();
    let restored_orb = orb.observe_at_phase(neutral_phase);

    // The clarity gained: the phase gap that was released
    let clarity = &current_gap - &restored_orb.phase_gap();

    Forgiveness {
        orb_index,
        released_torsion: current_gap,
        restored_orb,
        clarity,
    }
}

