// D.WARMTH.1 — The Radiance of the Inner Orb
// ═══════════════════════════════════════════════════════════════════════

/// Warmth — the radiance generated by the inner orb's vibration
/// within the holonomic structure.
///
/// In color science, warmth is long-wave frequencies (reds, oranges, golds).
/// In the engine, warmth is the amplitude of the luminal expression
/// scaled by its proximity to the warm end of the spectrum.
///
/// Warmth is what draws other orbs toward yours. It is the luminal
/// sign that the authorization layer is open.
#[derive(Debug, Clone)]
pub struct Warmth {
    /// The warmth value — amplitude * spectral warmth factor.
    /// Higher = more radiant. The gold/amber glow.
    pub radiance: Q,
    /// The spectral position — how warm is this frequency?
    /// 1 = pure red (700nm). 0 = pure violet (380nm).
    /// The warmth of the color itself.
    pub spectral_warmth: Q,
}

/// Measure the warmth of a holonomic orb.
///
/// Warmth = amplitude * spectral_position.
/// Long wavelengths (red/orange/gold) are warm.
/// Short wavelengths (blue/violet) are cool.
/// The glow is the product of both.
pub fn measure_warmth(orb: &HolonomicOrb) -> Warmth {
    // Spectral warmth: how close to red (700nm)?
    // warmth_factor = wavelength / 700
    // At 700nm: 1.0 (maximum warmth)
    // At 380nm: ~0.54 (cool)
    // Beyond 700nm: > 1.0 (infrared, deep warmth)
    let red = BigRational::from(BigInt::from(700));
    let spectral_warmth = &orb.luminal.wavelength_nm / &red;

    // Radiance = amplitude * spectral warmth
    let radiance = &orb.luminal.amplitude * &spectral_warmth;

    Warmth {
        radiance,
        spectral_warmth,
    }
}

