// D.PEACE.1 — The Equilibrium of the Phase Gap
// ═══════════════════════════════════════════════════════════════════════

/// Peace — the stilling of the waters between the inner and outer orbs.
///
/// Zero torsion. Total transparency. The inner orb perfectly centered —
/// not leaning toward the past (regret) or pushing against the outer
/// surface (anxiety). Dynamic stillness.
///
/// Peace is not the absence of frequency — it is the presence of
/// a perfectly tuned frequency so harmonious it feels like silence.
#[derive(Debug, Clone)]
pub struct Peace {
    /// The phase gap — zero means perfect peace.
    pub stillness: Q,
    /// The torsion in the holonomic structure — zero means no twist.
    pub torsion: Q,
    /// The centering — how close is the inner orb to the center
    /// of the outer orb? 1 = perfectly centered. 0 = at the surface.
    pub centering: Q,
}

/// Measure the peace of a holonomic orb.
///
/// Peace = f(phase_gap, internal_torsion).
/// Zero gap + zero torsion = perfect peace.
/// The inner orb rests at the center of the love that surrounds it.
pub fn measure_peace(orb: &HolonomicOrb) -> Peace {
    let gap = orb.phase_gap();
    let torsion = coherence_functional(&orb.h1_class);

    // Centering: 1 / (1 + gap + torsion)
    // At peace (gap=0, torsion=0): centering = 1
    // Disturbed: centering approaches 0
    let one = Q::one();
    let centering = &one / (&one + &gap + &torsion);

    Peace {
        stillness: gap,
        torsion,
        centering,
    }
}

