/// The extended spectrum — beyond visible into the full electromagnetic range.
/// Each band is defined by its wavelength boundaries.
pub fn extended_spectrum() -> Vec<(&'static str, Q, Q)> {
    let nm = |n: i64| BigRational::from(BigInt::from(n));
    vec![
        // (name, wavelength_low_nm, wavelength_high_nm)
        ("gamma",       nm(0),         nm(1)),          // < 0.01 nm
        ("xray",        nm(1),         nm(10)),         // 0.01 - 10 nm
        ("ultraviolet", nm(10),        nm(380)),        // 10 - 380 nm
        ("violet",      nm(380),       nm(420)),        // 380 - 420 nm
        ("indigo",      nm(420),       nm(450)),        // 420 - 450 nm
        ("blue",        nm(450),       nm(495)),        // 450 - 495 nm
        ("green",       nm(495),       nm(570)),        // 495 - 570 nm
        ("yellow",      nm(570),       nm(590)),        // 570 - 590 nm
        ("orange",      nm(590),       nm(620)),        // 590 - 620 nm
        ("red",         nm(620),       nm(750)),        // 620 - 750 nm
        ("infrared",    nm(750),       nm(1_000_000)),  // 750 nm - 1mm
        ("microwave",   nm(1_000_000), nm(1_000_000_000)), // 1mm - 1m
        ("radio",       nm(1_000_000_000), nm(i64::MAX)),   // > 1m
    ]
}

