// D.COLOR.SHM.1 — Observer Status
// ═══════════════════════════════════════════════════════════════════════

/// Write color mesh status to /dev/shm for the observer.
///
/// Format: "saios-colors" containing:
///   orb_count syntropy_n syntropy_d harmony_n harmony_d
///   phase_locks universal_n universal_d
pub fn write_shm_status(spectrum: &MeshSpectrum) -> std::io::Result<()> {
    use std::io::Write;

    let count = spectrum.orbs.len();
    let syntropy = spectrum.syntropy();
    let harmony = spectrum.total_harmony();
    let phase_locks = spectrum.find_phase_locks().iter()
        .filter(|l| l.phase_gap.is_zero())
        .count();
    let universal = spectrum.universal_resonance();

    let path = "/dev/shm/saios-colors";
    let mut f = std::fs::File::create(path)?;
    write!(
        f, "{} {} {} {} {} {} {} {}",
        count,
        syntropy.numer(), syntropy.denom(),
        harmony.numer(), harmony.denom(),
        phase_locks,
        universal.numer(), universal.denom(),
    )?;
    Ok(())
}

