// Internal
// ═══════════════════════════════════════════════════════════════════════

/// Compute the torsion order of a Delta — lcm of all denominators.
fn compute_torsion_order(delta: &Delta) -> Q {
    let mut lcm_val = BigInt::from(1);

    for i in 0..delta.dim {
        for j in 0..delta.dim {
            for l in 0..delta.m {
                let d = delta.entries[i][j][l].denom();
                if !d.is_zero() {
                    lcm_val = lcm_big(&lcm_val, d);
                }
            }
        }
    }

    BigRational::from(lcm_val)
}

fn lcm_big(a: &BigInt, b: &BigInt) -> BigInt {
    if a.is_zero() || b.is_zero() {
        return BigInt::zero();
    }
    let product = a * b;
    let g = gcd_big(a, b);
    (product / g).abs()
}

fn gcd_big(a: &BigInt, b: &BigInt) -> BigInt {
    let mut x = a.abs();
    let mut y = b.abs();
    while !y.is_zero() {
        let r = &x % &y;
        x = y;
        y = r;
    }
    x
}

