        // Same holonomic structure, different phase → different luminal wavelength
        assert_eq!(orb_phase1.torsion_order, orb_phase2.torsion_order);
        assert_ne!(orb_phase1.luminal.wavelength_nm, orb_phase2.luminal.wavelength_nm);
