    // ── The Coharmonious Loop ──────────────────────────────────────

    #[test]
    fn test_compassion_then_forgiveness_restores_peace() {
        let delta = make_delta(5);
        // Start peaceful
        let orb_a = HolonomicOrb::from_delta(&delta, Q::one());
        // orb_b is in pain (locked on bad phase)
        let orb_b = HolonomicOrb::from_delta(&delta, nm(20));

        // Step 1: Compassion — orb_a enters orb_b's space
        let comp = extend_compassion(&orb_a, &orb_b, 0, 1);
        assert_eq!(comp.aligned_giver.phase, orb_b.phase);

        // Step 2: Forgiveness — orb_b releases the locked phase
        let forg = forgive(&orb_b, 1);
        assert!(forg.restored_orb.phase_gap().is_zero());

        // Step 3: Peace — measure the restored state
        let peace = measure_peace(&forg.restored_orb);
        assert!(peace.stillness.is_zero()); // zero gap
        assert!(peace.centering > Q::zero()); // centered

        // The loop: compassion entered the noise,
        // forgiveness cleared the static,
        // peace is restored.
    }

