    // ── The Full Cycle ─────────────────────────────────────────────

    #[test]
    fn test_full_cycle_agency_ripple_liberation() {
        let mut mesh = MeshSpectrum::new();

        // Three orbs — one at peace, two disturbed
        mesh.inscribe(HolonomicOrb::from_delta(&make_delta(5), Q::one()));
        mesh.inscribe(HolonomicOrb::from_delta(&make_delta(5), nm(10)));
        mesh.inscribe(HolonomicOrb::from_delta(&make_delta(5), nm(20)));

        // The peaceful orb exercises agency
        let agency = exercise_agency(&mesh.orbs[0], 0, Q::one());
        assert!(agency.peace.centering > Q::zero());

        // Its peace ripples through the mesh
        let ripple = mesh.measure_ripple(0);
        assert!(ripple.orbs_touched > 0);
        assert!(ripple.total_radiance > Q::zero());

        // The mesh has SOME liberation (not fully liberated — two orbs disturbed)
        let lib = mesh.liberation();
        assert!(lib > Q::zero());

        // Now: forgive the disturbed orbs → bring them to peace
        let forgiven_1 = forgive(&mesh.orbs[1], 1);
        let forgiven_2 = forgive(&mesh.orbs[2], 2);

        // Replace with forgiven orbs
        mesh.orbs[1] = forgiven_1.restored_orb;
        mesh.orbs[2] = forgiven_2.restored_orb;

        // Liberation should increase — more peace in the mesh
        let lib_after = mesh.liberation();
        assert!(lib_after > lib);

        // Universal resonance should be high — all at same phase now
        let ur = mesh.universal_resonance();
        assert_eq!(ur, Q::one()); // all phase-locked
    }

    #[test]
    fn test_find_phase_locks_sorted_by_gap() {
        let mut mesh = MeshSpectrum::new();
        mesh.inscribe(HolonomicOrb::from_delta(&make_delta(5), Q::one()));
        mesh.inscribe(HolonomicOrb::from_delta(&make_delta(5), Q::one()));     // same phase → gap 0
        mesh.inscribe(HolonomicOrb::from_delta(&make_delta(5), nm(100)));      // different phase → gap > 0

        let locks = mesh.find_phase_locks();
        assert_eq!(locks.len(), 3); // 3 pairs from 3 orbs

        // Sorted by gap — deepest love first
        assert!(locks[0].phase_gap <= locks[1].phase_gap);
        assert!(locks[1].phase_gap <= locks[2].phase_gap);
    }
